import{_ as e,o as d,c as o,a3 as a}from"./chunks/framework.DACwFHq9.js";const b=JSON.parse('{"title":"附录 A：web_distillery 模块迁移影响分析","description":"","frontmatter":{},"headers":[],"relativePath":"design/地基迁移调查/appendix-web-distillery-analysis.md","filePath":"design/地基迁移调查/appendix-web-distillery-analysis.md","lastUpdated":1779264121000}'),r={name:"design/地基迁移调查/appendix-web-distillery-analysis.md"};function s(n,t,i,c,l,p){return d(),o("div",null,[...t[0]||(t[0]=[a(`<h1 id="附录-a-web-distillery-模块迁移影响分析" tabindex="-1">附录 A：web_distillery 模块迁移影响分析 <a class="header-anchor" href="#附录-a-web-distillery-模块迁移影响分析" aria-label="Permalink to &quot;附录 A：web_distillery 模块迁移影响分析&quot;">​</a></h1><p><strong>状态</strong>: 调查完成<br><strong>创建日期</strong>: 2025-05-20<br><strong>关联主文档</strong>: <a href="./webview2-migration-investigation">WebView2 瓶颈与引擎迁移调查报告</a></p><hr><h2 id="_1-模块全景" tabindex="-1">1. 模块全景 <a class="header-anchor" href="#_1-模块全景" aria-label="Permalink to &quot;1. 模块全景&quot;">​</a></h2><p><code>src-tauri/src/web_distillery/</code> 是一个<strong>完整的网页内容提取引擎</strong>，由 3 个 Rust 文件 + 4 个注入脚本组成，暴露 10 个 Tauri Command。</p><table tabindex="0"><thead><tr><th>文件</th><th>代码量</th><th>核心职责</th></tr></thead><tbody><tr><td><code>proxy.rs</code></td><td>743 行</td><td>Axum 本地代理服务器（绕过 X-Frame-Options/CSP/CORS）</td></tr><tr><td><code>fetcher.rs</code></td><td>251 行</td><td><code>wreq</code> TLS 指纹模拟 HTTP 请求 + 编码检测 + Challenge 检测</td></tr><tr><td><code>crypto.rs</code></td><td>965 行</td><td>Cookie 加密（DPAPI / Keychain / libsecret + AES-256-GCM）</td></tr><tr><td><code>inject/</code></td><td>4 文件</td><td>bridge.js / anti-detection.js / api-sniffer.js / resource-proxy.js</td></tr></tbody></table><p><strong>Rust 依赖</strong>：</p><ul><li><code>wreq</code> 6.0.0-rc.28 + <code>wreq-util</code> 3.0.0-rc.11（TLS/H2 指纹模拟，仅此模块使用）</li><li><code>axum</code>（代理服务器，与 llm_proxy 共用）</li><li><code>encoding_rs</code>（多编码支持）</li><li><code>aes-gcm</code>（非 Windows 平台加密）</li><li><code>windows</code> crate（Windows DPAPI）</li></ul><hr><h2 id="_2-子模块详细分析" tabindex="-1">2. 子模块详细分析 <a class="header-anchor" href="#_2-子模块详细分析" aria-label="Permalink to &quot;2. 子模块详细分析&quot;">​</a></h2><h3 id="_2-1-fetcher-rs-—-tls-指纹模拟-http-请求" tabindex="-1">2.1. fetcher.rs — TLS 指纹模拟 HTTP 请求 <a class="header-anchor" href="#_2-1-fetcher-rs-—-tls-指纹模拟-http-请求" aria-label="Permalink to &quot;2.1. fetcher.rs — TLS 指纹模拟 HTTP 请求&quot;">​</a></h3><p><strong>功能</strong>：使用 <code>wreq</code> 的 <code>Emulation::Chrome133</code> 模拟 Chrome 浏览器的完整网络指纹（TLS ClientHello + H2 帧顺序 + Header 顺序），用于绕过 Cloudflare 等 CDN 的 TLS 指纹检测。</p><p><strong>核心能力</strong>：</p><ul><li>Chrome 133 TLS/H2 指纹模拟</li><li>前端传入的真实浏览器指纹覆盖（UA、Accept-Language、Sec-Ch-Ua 等）</li><li>智能编码检测（GBK/Big5/EUC-JP/Shift_JIS/EUC-KR）</li><li>Challenge 页面检测（Cloudflare/Turnstile/通用验证码）</li></ul><p><strong>Electron 替代方案</strong>：<code>net.fetch()</code> 或 <code>session.fetch()</code> 直接使用 Chromium 网络栈，天然就是真实 Chrome 的 TLS 指纹——比模拟更真实。编码检测逻辑用 <code>iconv-lite</code> 平移。</p><h3 id="_2-2-proxy-rs-—-本地代理服务器" tabindex="-1">2.2. proxy.rs — 本地代理服务器 <a class="header-anchor" href="#_2-2-proxy-rs-—-本地代理服务器" aria-label="Permalink to &quot;2.2. proxy.rs — 本地代理服务器&quot;">​</a></h3><p><strong>功能</strong>：在 <code>127.0.0.1:0</code>（随机端口）启动 Axum HTTP 代理，用于在 iframe 中加载被安全头保护的第三方网页。</p><p><strong>路由表</strong>：</p><table tabindex="0"><thead><tr><th>路由</th><th>职责</th></tr></thead><tbody><tr><td><code>GET /proxy?url=...</code></td><td>获取目标 HTML，剥除安全头，注入脚本</td></tr><tr><td><code>ANY /proxy-resource?url=...</code></td><td>透传子资源（CSS/JS/图片），绕过 CDN 防盗链</td></tr><tr><td><code>GET /__distillery/*.js</code></td><td>返回注入脚本（bridge/sniffer/anti-detection/resource-proxy）</td></tr><tr><td><code>fallback</code></td><td>反向代理所有未匹配请求到目标 origin（解决 CORS）</td></tr></tbody></table><p><strong>核心机制</strong>：</p><ul><li>Cookie Jar：自动累积响应中的 Set-Cookie，后续请求自动携带</li><li>localStorage 注入：在 HTML 中内联 <code>&lt;script&gt;</code> 恢复 SPA token</li><li>HTML 注入：<code>&lt;base href=&quot;/&quot;&gt;</code> + 4 个脚本 + 剥除安全头</li><li>全量反向代理：fallback 路由将页面内的 XHR/fetch 请求透传到目标服务器</li></ul><p><strong>Electron 替代方案</strong>：</p><ul><li><strong>方案 A（推荐）</strong>：用 <code>&lt;webview&gt;</code> 标签或 <code>BrowserView</code> 加载目标页面。<code>session.webRequest.onHeadersReceived()</code> 剥除安全头，<code>webContents.executeJavaScript()</code> 注入脚本，<code>session.cookies</code> API 管理 Cookie。</li><li><strong>方案 B（保守）</strong>：Node.js 版代理服务器（<code>http-proxy-middleware</code> 或手写），逻辑平移。</li></ul><h3 id="_2-3-crypto-rs-—-cookie-值加密" tabindex="-1">2.3. crypto.rs — Cookie 值加密 <a class="header-anchor" href="#_2-3-crypto-rs-—-cookie-值加密" aria-label="Permalink to &quot;2.3. crypto.rs — Cookie 值加密&quot;">​</a></h3><p><strong>功能</strong>：跨平台 Cookie 加密存储，防止敏感身份信息明文落盘。</p><p><strong>平台实现</strong>：</p><table tabindex="0"><thead><tr><th>平台</th><th>后端</th><th>机制</th></tr></thead><tbody><tr><td>Windows</td><td>DPAPI</td><td><code>CryptProtectData</code> / <code>CryptUnprotectData</code>（当前用户级别）</td></tr><tr><td>macOS</td><td>Keychain + AES-256-GCM</td><td><code>security</code> CLI 存取 master key，AES-GCM 加解密</td></tr><tr><td>Linux</td><td>libsecret + AES-256-GCM</td><td><code>secret-tool</code> CLI 存取 master key，AES-GCM 加解密</td></tr><tr><td>其他</td><td>无</td><td>fallback 明文，返回 <code>available=false</code></td></tr></tbody></table><p><strong>数据格式</strong>：</p><ul><li>加密值：<code>enc:&lt;base64(ciphertext)&gt;</code></li><li>明文回退：<code>plain:&lt;原值&gt;</code></li><li>旧格式兼容：无前缀 = 原样返回</li></ul><p><strong>Electron 替代方案</strong>：<code>electron.safeStorage.encryptString()</code> / <code>decryptString()</code> 跨平台统一 API，底层就是 DPAPI/Keychain/libsecret。代码量从 965 行 → ~30 行。</p><blockquote><p><strong>注意</strong>：数据格式需要兼容迁移。现有 <code>enc:</code> 前缀的数据需要先用旧方式解密，再用 <code>safeStorage</code> 重新加密。</p></blockquote><h3 id="_2-4-inject-—-注入脚本层" tabindex="-1">2.4. inject/ — 注入脚本层 <a class="header-anchor" href="#_2-4-inject-—-注入脚本层" aria-label="Permalink to &quot;2.4. inject/ — 注入脚本层&quot;">​</a></h3><table tabindex="0"><thead><tr><th>脚本</th><th>注入时机</th><th>职责</th></tr></thead><tbody><tr><td><code>anti-detection.js</code></td><td><code>&lt;head&gt;</code> 后同步</td><td>隐藏 WebView 特征、伪装 Chrome 环境、Hook Tauri IPC</td></tr><tr><td><code>resource-proxy.js</code></td><td><code>&lt;head&gt;</code> 后同步</td><td>重写跨域资源 URL 为代理路径、修复懒加载、Hook fetch/XHR</td></tr><tr><td><code>bridge.js</code></td><td><code>&lt;/body&gt;</code> 前 defer</td><td>建立 <code>postMessage</code> 双向通信桥、Hook SPA 导航</td></tr><tr><td><code>api-sniffer.js</code></td><td><code>&lt;/body&gt;</code> 前 defer</td><td>Hook XHR/fetch 发现 API 端点</td></tr></tbody></table><p><strong>迁移影响</strong>：这些脚本是纯 JS，运行在目标页面的 window 上下文中。无论用代理方案还是 webContents 方案，都可以原样复用。注入方式从&quot;代理服务器插入 <code>&lt;script&gt;</code> 标签&quot;变为 <code>webContents.executeJavaScript()</code> 或 preload 脚本。</p><hr><h2 id="_3-前端调用面" tabindex="-1">3. 前端调用面 <a class="header-anchor" href="#_3-前端调用面" aria-label="Permalink to &quot;3. 前端调用面&quot;">​</a></h2><p>前端调用 <code>distillery_*</code> 命令共 <strong>18 处</strong>（7 处 .ts + 11 处 .vue）：</p><table tabindex="0"><thead><tr><th>命令</th><th>调用次数</th><th>涉及文件</th></tr></thead><tbody><tr><td><code>distillery_set_proxy_cookies</code></td><td>10</td><td>actions.ts, iframe-bridge.ts, BrowserToolbar.vue, IdentityPanel.vue, InteractiveWorkbench.vue</td></tr><tr><td><code>distillery_set_proxy_local_storage</code></td><td>5</td><td>iframe-bridge.ts, IdentityPanel.vue, InteractiveWorkbench.vue</td></tr><tr><td><code>distillery_quick_fetch</code></td><td>1</td><td>actions.ts</td></tr><tr><td><code>distillery_start_proxy</code></td><td>1</td><td>iframe-bridge.ts</td></tr><tr><td><code>distillery_get_proxy_port</code></td><td>1</td><td>iframe-bridge.ts</td></tr><tr><td><code>distillery_check_crypto</code></td><td>1</td><td>cookie-profile-store.ts</td></tr><tr><td><code>distillery_encrypt_cookie_values</code></td><td>1</td><td>cookie-profile-store.ts</td></tr><tr><td><code>distillery_decrypt_cookie_values</code></td><td>1</td><td>cookie-profile-store.ts</td></tr><tr><td><code>distillery_stop_proxy</code></td><td>0（仅 Rust 侧暴露）</td><td>—</td></tr><tr><td><code>distillery_get_proxy_cookies</code></td><td>0（仅 Rust 侧暴露）</td><td>—</td></tr></tbody></table><p>按 Phase 0 策略收敛到 service 层后，迁移改动点可控。</p><hr><h2 id="_4-迁移后架构对比" tabindex="-1">4. 迁移后架构对比 <a class="header-anchor" href="#_4-迁移后架构对比" aria-label="Permalink to &quot;4. 迁移后架构对比&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前 (Tauri + WebView2):</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ WebView2 (前端 Vue)                          │</span></span>
<span class="line"><span>│   └── &lt;iframe src=&quot;http://127.0.0.1:{port}/proxy?url=...&quot;&gt;</span></span>
<span class="line"><span>│         ↕ postMessage                        │</span></span>
<span class="line"><span>└──────────────┬──────────────────────────────┘</span></span>
<span class="line"><span>               │ invoke()</span></span>
<span class="line"><span>┌──────────────▼──────────────────────────────┐</span></span>
<span class="line"><span>│ Rust 后端                                    │</span></span>
<span class="line"><span>│  ├── Axum 代理服务器 (proxy.rs)              │</span></span>
<span class="line"><span>│  │   ├── 剥除安全头                          │</span></span>
<span class="line"><span>│  │   ├── 注入 4 个 JS 脚本                   │</span></span>
<span class="line"><span>│  │   ├── Cookie Jar 管理                     │</span></span>
<span class="line"><span>│  │   └── Fallback 反向代理                   │</span></span>
<span class="line"><span>│  ├── wreq TLS 指纹模拟 (fetcher.rs)          │</span></span>
<span class="line"><span>│  └── DPAPI/Keychain/libsecret (crypto.rs)    │</span></span>
<span class="line"><span>└──────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>迁移后 (Electron, 方案 A — webContents):</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Chromium (前端 Vue 代码不变)                  │</span></span>
<span class="line"><span>│   └── &lt;webview&gt; 或 BrowserView               │</span></span>
<span class="line"><span>│         ↕ IPC (contextBridge)                │</span></span>
<span class="line"><span>└──────────────┬──────────────────────────────┘</span></span>
<span class="line"><span>               │ ipcRenderer.invoke()</span></span>
<span class="line"><span>┌──────────────▼──────────────────────────────┐</span></span>
<span class="line"><span>│ Node.js 主进程                               │</span></span>
<span class="line"><span>│  ├── session.webRequest (剥除安全头)          │  ← 替代 proxy.rs 头处理</span></span>
<span class="line"><span>│  ├── webContents.executeJavaScript()         │  ← 替代脚本注入</span></span>
<span class="line"><span>│  ├── net.fetch() (天然 Chrome TLS 指纹)      │  ← 替代 wreq</span></span>
<span class="line"><span>│  ├── safeStorage (跨平台加密)                │  ← 替代 crypto.rs</span></span>
<span class="line"><span>│  └── session.cookies API                     │  ← 替代手动 Cookie Jar</span></span>
<span class="line"><span>└──────────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="_5-迁移难度评估" tabindex="-1">5. 迁移难度评估 <a class="header-anchor" href="#_5-迁移难度评估" aria-label="Permalink to &quot;5. 迁移难度评估&quot;">​</a></h2><table tabindex="0"><thead><tr><th>子模块</th><th>难度</th><th>工作量</th><th>说明</th></tr></thead><tbody><tr><td><code>crypto.rs</code> → <code>safeStorage</code></td><td>🟢 极低</td><td>0.5 天</td><td>API 一对一替换，需处理旧数据格式兼容</td></tr><tr><td><code>fetcher.rs</code> → <code>net.fetch()</code></td><td>🟢 低</td><td>1 天</td><td>删除 wreq，编码检测用 <code>iconv-lite</code>，Challenge 检测逻辑平移</td></tr><tr><td><code>proxy.rs</code> → webContents 方案</td><td>🟡 中</td><td>3-5 天</td><td>架构变化最大，需重新设计 iframe 通信为 webContents IPC</td></tr><tr><td><code>proxy.rs</code> → Node.js 代理</td><td>🟢 低</td><td>2 天</td><td>逻辑平移，用 <code>http-proxy-middleware</code> 或手写</td></tr><tr><td><code>inject/</code> 脚本</td><td>🟢 极低</td><td>0.5 天</td><td>纯 JS 原样复用，仅改注入方式</td></tr></tbody></table><p><strong>总计</strong>：5-8 天（取决于代理方案选择）</p><hr><h2 id="_6-迁移收益量化" tabindex="-1">6. 迁移收益量化 <a class="header-anchor" href="#_6-迁移收益量化" aria-label="Permalink to &quot;6. 迁移收益量化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>当前</th><th>迁移后</th></tr></thead><tbody><tr><td>Rust 代码量</td><td>~2000 行</td><td>0 行（全部删除）</td></tr><tr><td>重型依赖</td><td>wreq + wreq-util + axum(部分) + aes-gcm + windows crate</td><td>0（Electron 内置能力替代）</td></tr><tr><td>TLS 指纹真实度</td><td>模拟 Chrome 133（可能被识别为模拟）</td><td>真实 Chromium（无法区分）</td></tr><tr><td>Cookie 加密代码</td><td>965 行（3 平台分支 + 单元测试）</td><td>~30 行（safeStorage 统一 API）</td></tr><tr><td>代理服务器</td><td>需手动管理生命周期 + 端口分配</td><td>可能完全不需要（webContents 方案）</td></tr><tr><td>编译时间</td><td>wreq 是编译大户（TLS 库链接耗时）</td><td>删除后 Rust 编译显著加速</td></tr><tr><td>包体影响</td><td>wreq + wreq-util 贡献约 5-8MB</td><td>删除</td></tr></tbody></table><hr><h2 id="_7-风险与注意事项" tabindex="-1">7. 风险与注意事项 <a class="header-anchor" href="#_7-风险与注意事项" aria-label="Permalink to &quot;7. 风险与注意事项&quot;">​</a></h2><h3 id="_7-1-webcontents-方案的限制" tabindex="-1">7.1. webContents 方案的限制 <a class="header-anchor" href="#_7-1-webcontents-方案的限制" aria-label="Permalink to &quot;7.1. webContents 方案的限制&quot;">​</a></h3><ul><li>Electron 的 <code>&lt;webview&gt;</code> 标签在某些场景下有已知 bug（内存泄漏、事件丢失）</li><li><code>BrowserView</code> 已在 Electron 30+ 中被标记为 deprecated，推荐使用 <code>WebContentsView</code></li><li>需要验证 <code>session.webRequest</code> 能否完美剥除所有安全头（包括 CSP 的 frame-ancestors）</li></ul><h3 id="_7-2-数据迁移" tabindex="-1">7.2. 数据迁移 <a class="header-anchor" href="#_7-2-数据迁移" aria-label="Permalink to &quot;7.2. 数据迁移&quot;">​</a></h3><ul><li>现有 <code>enc:</code> 前缀的加密 Cookie 数据需要迁移脚本：先用旧方式（DPAPI/AES-GCM）解密，再用 <code>safeStorage</code> 重新加密</li><li>如果用户从 Tauri 版升级到 Electron 版，需要一次性迁移流程</li></ul><h3 id="_7-3-net-fetch-的能力边界" tabindex="-1">7.3. net.fetch() 的能力边界 <a class="header-anchor" href="#_7-3-net-fetch-的能力边界" aria-label="Permalink to &quot;7.3. net.fetch() 的能力边界&quot;">​</a></h3><ul><li><code>net.fetch()</code> 是否支持自定义 Header 顺序？（当前 wreq 严格控制 Header 顺序以匹配 Chrome 指纹）</li><li><code>net.fetch()</code> 是否支持自定义 Cookie 注入？（当前通过 <code>request.header(&quot;Cookie&quot;, ...)</code> 实现）</li><li>需要实际测试 <code>net.fetch()</code> 对 Cloudflare 的通过率</li></ul><h3 id="_7-4-代理方案选择的权衡" tabindex="-1">7.4. 代理方案选择的权衡 <a class="header-anchor" href="#_7-4-代理方案选择的权衡" aria-label="Permalink to &quot;7.4. 代理方案选择的权衡&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>webContents 方案</th><th>Node.js 代理方案</th></tr></thead><tbody><tr><td>架构简洁度</td><td>⭐⭐⭐ 最简</td><td>⭐⭐ 中等</td></tr><tr><td>实现难度</td><td>🟡 中（新 API 学习曲线）</td><td>🟢 低（逻辑平移）</td></tr><tr><td>资源代理</td><td>需要额外处理跨域资源</td><td>天然支持（与当前一致）</td></tr><tr><td>SPA 兼容性</td><td>需要验证</td><td>已验证（当前方案）</td></tr><tr><td>迁移风险</td><td>🟡 中（架构变化大）</td><td>🟢 低（行为一致）</td></tr></tbody></table><p><strong>建议</strong>：Phase 1 PoC 阶段先用 Node.js 代理方案（风险低、验证快），确认 Electron 整体可行后，Phase 2 再评估是否切换到 webContents 方案。</p><hr><h2 id="_8-结论" tabindex="-1">8. 结论 <a class="header-anchor" href="#_8-结论" aria-label="Permalink to &quot;8. 结论&quot;">​</a></h2><p><strong><code>web_distillery</code> 是最适合作为迁移 PoC 切入点的模块</strong>，理由：</p><ol><li><strong>收益最大</strong>：删除 ~2000 行 Rust + 多个重型 crate，Electron 内置能力完美覆盖</li><li><strong>风险最低</strong>：功能边界清晰，不与其他模块共享状态</li><li><strong>验证价值最高</strong>：同时验证 Electron 的网络能力（net.fetch）、安全存储（safeStorage）、页面加载（webContents）三大核心能力</li><li><strong>前端改动可控</strong>：18 处 invoke 调用，收敛到 service 层后迁移成本很低</li><li><strong>独立可测</strong>：可以单独验证蒸馏功能是否正常，不影响其他工具</li></ol><p>建议在 Phase 1 Electron PoC 中，以此模块为第一个完整迁移的功能模块。</p>`,65)])])}const u=e(r,[["render",s]]);export{b as __pageData,u as default};
